interface.definition:
a!localVariables(
  local!searchTerm,
  local!userFilter,
  {
    #"SYSTEM_SYSRULES_sectionLayout_v1"(
      label: "Activity History",
      contents: #"SYSTEM_SYSRULES_columnsLayout"(
        columns: {
          #"SYSTEM_SYSRULES_columnLayout"(
            contents: {
              #"SYSTEM_SYSRULES_pickerFieldUsers"(
                labelPosition: "COLLAPSED",
                placeholder: "Select a user to filter on their activity",
                groupFilter: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1058640",
                maxSelections: 1,
                value: local!userFilter,
                saveInto: local!userFilter
              )
            }
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            contents: {
              #"SYSTEM_SYSRULES_textField"(
                labelPosition: "COLLAPSED",
                placeholder: "Search activity history actions and details",
                refreshAfter: "KEYPRESS",
                value: local!searchTerm,
                saveInto: local!searchTerm
              )
            }
          )
        }
      )
    ),
    #"SYSTEM_SYSRULES_sectionLayout_v1"(
      contents: {
        #"SYSTEM_SYSRULES_gridField_v3"(
          labelPosition: "COLLAPSED",
          emptyGridMessage: "No activity entries available",
          data: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1058849"(
            recordId: ri!id,
            searchTerm: local!searchTerm,
            userFilter: local!userFilter,
            pagingInfo: fv!pagingInfo
          ),
          columns: {
            #"SYSTEM_SYSRULES_gridColumn"(
              label: "User",
              sortField: "who",
              value: #"SYSTEM_SYSRULES_linkField"(links: { #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1058760"(label: fv!row.who, username: fv!row.who) })
            ),
            #"SYSTEM_SYSRULES_gridColumn"(
              label: "Action",
              sortField: "action",
              value: fv!row.action
            ),
            #"SYSTEM_SYSRULES_gridColumn"(
              label: "Details",
              sortField: "details",
              value: fv!row.details
            ),
            #"SYSTEM_SYSRULES_gridColumn"(
              label: "On",
              sortField: "when",
              value: #"_a-0000ed02-f63d-8000-9bea-011c48011c48_1058684"(fv!row.when),
              align: "END"
            )
          },
          pageSize: 25,
          initialSorts: { #"SYSTEM_SYSRULES_sortInfo"("when", false) }
        )
      }
    )
  }
)
